# solution.py
"""Team Collaboration Manager.

A self-contained, thread-safe, in-memory team collaboration backend that
supports user management, project and task tracking, threaded messaging with
attachments, a performance dashboard (completion metrics + peer ratings) and
exportable reports (CSV / PDF).

The implementation uses only the Python standard library and is organised
around a single shared re-entrant lock so that every store/service exposed by
the manager observes a consistent view of the data under concurrency.
"""

import copy
import csv
import enum
import io
import threading
from collections import defaultdict
from dataclasses import dataclass, field
from datetime import datetime
from typing import Any, Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not allowed to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(enum.Enum):
    MEMBER = "member"
    ADMIN = "admin"
    GUEST = "guest"


class TaskStatus(enum.Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(enum.Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Stores / services (share a single lock with the manager)
# ---------------------------------------------------------------------------
class _BaseStore:
    """Common base that holds a reference to the shared lock."""

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id: Dict[int, Task] = {}
        self._by_project: Dict[int, set] = defaultdict(set)
        self._by_assignee: Dict[int, set] = defaultdict(set)


class _MessageStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id: Dict[int, Message] = {}
        self._by_project: Dict[int, set] = defaultdict(set)
        self._by_task: Dict[int, set] = defaultdict(set)


class _PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, set] = defaultdict(set)


class _ReportService(_BaseStore):
    """Stateless reporting service; exists so it can share the lock."""


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Facade coordinating all collaboration features.

    Parameters
    ----------
    now:
        Optional callable returning the "current" :class:`datetime`. Injecting
        a deterministic clock makes time-dependent behaviour testable.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        # Sub-stores all share the single re-entrant lock.
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportService(self._lock)

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------
    def _new_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    @staticmethod
    def _copy(obj: Any) -> Any:
        return copy.deepcopy(obj)

    @staticmethod
    def _copy_list(items) -> list:
        return [copy.deepcopy(item) for item in items]

    @staticmethod
    def _valid_email(email: Any) -> bool:
        if not isinstance(email, str):
            return False
        email = email.strip()
        if not email or "@" not in email:
            return False
        local, _, domain = email.partition("@")
        return bool(local) and bool(domain)

    def _require_user(self, user_id: int) -> User:
        user = self.users._by_id.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects._by_id.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks._by_id.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages._by_id.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    def _tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = self.tasks._by_assignee.get(user_id, set())
        return [self.tasks._by_id[i] for i in ids if i in self.tasks._by_id]

    # ==================================================================
    # User management
    # ==================================================================
    def register_user(self, username, email, role: UserRole = UserRole.MEMBER) -> User:
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("username must be a non-empty string")
            if not self._valid_email(email):
                raise ValidationError("email must contain '@'")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self.users._by_username:
                raise DuplicateError("username already exists")
            if email in self.users._by_email:
                raise DuplicateError("email already exists")

            user = User(
                id=self._new_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._by_id[user.id] = user
            self.users._by_username[username] = user.id
            self.users._by_email[email] = user.id
            return self._copy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return self._copy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return self._copy_list(
                self.users._by_id[i] for i in sorted(self.users._by_id)
            )

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username must be a non-empty string")
                holder = self.users._by_username.get(username)
                if holder is not None and holder != user_id:
                    raise DuplicateError("username already exists")
            if email is not None:
                if not self._valid_email(email):
                    raise ValidationError("email must contain '@'")
                holder = self.users._by_email.get(email)
                if holder is not None and holder != user_id:
                    raise DuplicateError("email already exists")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                self.users._by_username.pop(user.username, None)
                user.username = username
                self.users._by_username[username] = user_id
            if email is not None and email != user.email:
                self.users._by_email.pop(user.email, None)
                user.email = email
                self.users._by_email[email] = user_id
            if role is not None:
                user.role = role
            return self._copy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects._by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for task in self._tasks_for_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task assigned")

            # Detach any remaining (completed) tasks from the assignee index.
            for task in self._tasks_for_assignee(user_id):
                task.assignee_id = None
            self.tasks._by_assignee.pop(user_id, None)

            self.users._by_username.pop(user.username, None)
            self.users._by_email.pop(user.email, None)
            self.users._by_id.pop(user_id, None)

    # ==================================================================
    # Project management
    # ==================================================================
    def create_project(
        self, name, start_date, end_date, owner_id, description: str = ""
    ) -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._new_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description,
                created_at=self._now(),
            )
            self.projects._by_id[project.id] = project
            return self._copy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return self._copy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return self._copy_list(
                self.projects._by_id[i] for i in sorted(self.projects._by_id)
            )

    def update_project(
        self, project_id, name=None, start_date=None, end_date=None, description=None
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name if name is None else name
            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            new_desc = project.description if description is None else description

            if not isinstance(new_name, str) or not new_name.strip():
                raise ValidationError("project name must be a non-empty string")
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            project.description = new_desc
            return self._copy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks._by_project.get(project_id, set()))
            for task_id in task_ids:
                task = self.tasks._by_id.pop(task_id, None)
                if task is None:
                    continue
                if task.assignee_id is not None:
                    self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
                # Remove any messages attached to the task.
                msg_ids = list(self.messages._by_task.get(task_id, set()))
                for msg_id in msg_ids:
                    self.messages._by_id.pop(msg_id, None)
                self.messages._by_task.pop(task_id, None)
            self.tasks._by_project.pop(project_id, None)

            msg_ids = list(self.messages._by_project.get(project_id, set()))
            for msg_id in msg_ids:
                self.messages._by_id.pop(msg_id, None)
            self.messages._by_project.pop(project_id, None)

            self.projects._by_id.pop(project_id, None)

    # ==================================================================
    # Task management
    # ==================================================================
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be a non-empty string")
            project = self._require_project(project_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            if assignee_id is not None:
                self._require_user(assignee_id)

            task = Task(
                id=self._new_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks._by_id[task.id] = task
            self.tasks._by_project[project_id].add(task.id)
            if assignee_id is not None:
                self.tasks._by_assignee[assignee_id].add(task.id)
            return self._copy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return self._copy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.tasks._by_project.get(project_id, set()))
            return self._copy_list(self.tasks._by_id[i] for i in ids)

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self.tasks._by_assignee.get(user_id, set()))
            return self._copy_list(self.tasks._by_id[i] for i in ids)

    def _set_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        if task.assignee_id is not None:
            self.tasks._by_assignee.get(task.assignee_id, set()).discard(task.id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.tasks._by_assignee[assignee_id].add(task.id)

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._copy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._copy(task)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._copy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return self._copy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return self._copy(task)

    # ==================================================================
    # Messaging
    # ==================================================================
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            attachments = attachments or []
            has_body = isinstance(body, str) and body.strip() != ""
            if not has_body and not attachments:
                raise ValidationError("message must have a body or an attachment")

            if parent_id is not None:
                self._require_message(parent_id)

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=fname,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for (fname, data) in attachments
            ]
            message = Message(
                id=self._new_id(),
                author_id=author_id,
                body=body if body is not None else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
            )
            self.messages._by_id[message.id] = message
            if project_id is not None:
                self.messages._by_project[project_id].add(message.id)
            if task_id is not None:
                self.messages._by_task[task_id].add(message.id)
            return self._copy(message)

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit the message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body must be a non-empty string")
            message.body = new_body
            message.edited_at = self._now()
            return self._copy(message)

    def add_attachment(
        self, message_id: int, user_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be a non-empty string")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._now(),
                )
            )
            return self._copy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.messages._by_project.get(project_id, set()))
            return self._copy_list(self.messages._by_id[i] for i in ids)

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self.messages._by_task.get(task_id, set()))
            return self._copy_list(self.messages._by_id[i] for i in ids)

    def delete_message(self, message_id: int, user_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete the message")
            if message.project_id is not None:
                self.messages._by_project.get(message.project_id, set()).discard(
                    message_id
                )
            if message.task_id is not None:
                self.messages._by_task.get(message.task_id, set()).discard(message_id)
            self.messages._by_id.pop(message_id, None)

    # ==================================================================
    # Performance dashboard
    # ==================================================================
    @staticmethod
    def _completion_seconds(task: Task) -> Optional[float]:
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = [
                d
                for d in (self._completion_seconds(t) for t in self._tasks_for_assignee(user_id))
                if d is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self, rater_id: int, ratee_id: int, score: int, feedback: str = "", task_id=None
    ) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            if isinstance(score, bool) or not isinstance(score, int) or not (1 <= score <= 5):
                raise ValidationError("score must be an integer between 1 and 5")
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")

            rating = Rating(
                id=self._new_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._by_id[rating.id] = rating
            self.performance._by_ratee[ratee_id].add(rating.id)
            return self._copy(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        ids = sorted(self.performance._by_ratee.get(user_id, set()))
        return [self.performance._by_id[i] for i in ids]

    def get_ratings_summary(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": self._copy_list(ratings),
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            durations = [
                d
                for d in (self._completion_seconds(t) for t in tasks)
                if d is not None
            ]
            avg_time = sum(durations) / len(durations) if durations else None

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ==================================================================
    # Reports
    # ==================================================================
    def _stats_for_tasks(self, tasks: List[Task]) -> Dict[str, Any]:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
        not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
        durations = [
            d for d in (self._completion_seconds(t) for t in tasks) if d is not None
        ]
        avg_time = sum(durations) / len(durations) if durations else None
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": avg_time,
        }

    def project_progress_report(self, project_id: int) -> Dict[str, Any]:
        with self._lock:
            project = self._require_project(project_id)
            ids = sorted(self.tasks._by_project.get(project_id, set()))
            tasks = [self.tasks._by_id[i] for i in ids]

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, Any] = {}
            grouped: Dict[int, List[Task]] = defaultdict(list)
            for task in tasks:
                if task.assignee_id is not None:
                    grouped[task.assignee_id].append(task)
            for assignee_id, assignee_tasks in grouped.items():
                per_assignee[assignee_id] = self._stats_for_tasks(assignee_tasks)

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id: Optional[int] = None) -> Dict[str, Any]:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                task_ids = self.tasks._by_project.get(project_id, set())
                scoped_tasks = [self.tasks._by_id[i] for i in task_ids]
                user_ids = sorted(
                    {t.assignee_id for t in scoped_tasks if t.assignee_id is not None}
                )
                tasks_by_user = defaultdict(list)
                for task in scoped_tasks:
                    if task.assignee_id is not None:
                        tasks_by_user[task.assignee_id].append(task)
            else:
                user_ids = sorted(self.users._by_id)
                tasks_by_user = {
                    uid: self._tasks_for_assignee(uid) for uid in user_ids
                }

            rows = []
            for uid in user_ids:
                user = self.users._by_id.get(uid)
                stats = self._stats_for_tasks(list(tasks_by_user.get(uid, [])))
                ratings = self._ratings_for(uid)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                rows.append(
                    {
                        "user_id": uid,
                        "username": user.username if user else "",
                        "total_tasks": stats["total_tasks"],
                        "completed_tasks": stats["completed_tasks"],
                        "in_progress_tasks": stats["in_progress_tasks"],
                        "not_started_tasks": stats["not_started_tasks"],
                        "completion_rate": stats["completion_rate"],
                        "average_completion_time": stats["average_completion_time"],
                        "rating_count": rating_count,
                        "rating_average": rating_average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope": "global" if project_id is None else project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            user = self._require_user(user_id)
            tasks = sorted(self._tasks_for_assignee(user_id), key=lambda t: t.id)
            stats = self._stats_for_tasks(tasks)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "deadline": t.deadline.isoformat() if t.deadline else "",
                    "started_at": t.started_at.isoformat() if t.started_at else "",
                    "completed_at": t.completed_at.isoformat() if t.completed_at else "",
                }
                for t in tasks
            ]
            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }
            report.update(stats)
            return report

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report: Dict[str, Any], fmt: ReportFormat):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    @staticmethod
    def _report_to_csv(report: Dict[str, Any]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rtype = report.get("report_type")

        if rtype == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "in_progress_tasks",
                "not_started_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in header])
        elif rtype == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "task_id",
                "title",
                "status",
                "project_id",
                "deadline",
                "started_at",
                "completed_at",
            ]
            writer.writerow(header)
            for row in report.get("tasks", []):
                writer.writerow([row.get(col, "") for col in header])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                if isinstance(value, (dict, list)):
                    writer.writerow([key, _flatten(value)])
                else:
                    writer.writerow([key, value])
        return buffer.getvalue()

    @staticmethod
    def _report_to_pdf(report: Dict[str, Any]) -> bytes:
        lines = _report_text_lines(report)
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Helpers for report serialisation
# ---------------------------------------------------------------------------
def _flatten(value: Any) -> str:
    if isinstance(value, dict):
        return "; ".join("{0}={1}".format(k, v) for k, v in value.items())
    if isinstance(value, list):
        parts = []
        for item in value:
            if isinstance(item, dict):
                parts.append(
                    "(" + ", ".join("{0}={1}".format(k, v) for k, v in item.items()) + ")"
                )
            else:
                parts.append(str(item))
        return "; ".join(parts)
    return str(value)


def _report_text_lines(report: Dict[str, Any]) -> List[str]:
    lines = ["HealthConnect / Team Collaboration Report"]
    rtype = report.get("report_type", "report")
    lines.append("Type: {0}".format(rtype))
    for key, value in report.items():
        if key == "report_type":
            continue
        if key in ("rows", "tasks") and isinstance(value, list):
            lines.append("{0}:".format(key))
            for item in value:
                if isinstance(item, dict):
                    lines.append(
                        "  - "
                        + ", ".join("{0}={1}".format(k, v) for k, v in item.items())
                    )
                else:
                    lines.append("  - {0}".format(item))
        elif isinstance(value, (dict, list)):
            lines.append("{0}: {1}".format(key, _flatten(value)))
        else:
            lines.append("{0}: {1}".format(key, value))
    return lines


def _pdf_escape(text: str) -> str:
    return (
        text.replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal, structurally valid single-page PDF document."""
    if not lines:
        lines = [""]

    content_ops = ["BT", "/F1 11 Tf", "14 TL", "50 760 Td"]
    for index, line in enumerate(lines):
        safe = _pdf_escape(str(line))[:200]
        if index == 0:
            content_ops.append("({0}) Tj".format(safe))
        else:
            content_ops.append("T*")
            content_ops.append("({0}) Tj".format(safe))
    content_ops.append("ET")
    content_stream = "\n".join(content_ops).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        ),
        b"<< /Length "
        + str(len(content_stream)).encode("ascii")
        + b" >>\nstream\n"
        + content_stream
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray()
    pdf += b"%PDF-1.4\n"
    offsets = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(number).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_offset = len(pdf)
    count = len(objects) + 1
    pdf += b"xref\n"
    pdf += b"0 " + str(count).encode("ascii") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n"
    pdf += b"<< /Size " + str(count).encode("ascii") + b" /Root 1 0 R >>\n"
    pdf += b"startxref\n"
    pdf += str(xref_offset).encode("ascii") + b"\n"
    pdf += b"%%EOF\n"
    return bytes(pdf)


